body.script:
(function() {
  function loadKatex() {
    const link = document.querySelector('link[href="https://d4tuoctqmanu0.cloudfront.net/katex.min.css"]');
    if (link) link.rel = 'stylesheet';
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', loadKatex);
  } else {
    loadKatex();
  }
})();

div.script:
(function () {
  try {
    if (window.__mintlifyInitialSidebarScrollDone) return;
    window.__mintlifyInitialSidebarScrollDone = true;

    var path = (window.location.pathname || '/').split('#')[0].split('?')[0];
    if (path.endsWith('/index')) path = path.slice(0, -6);
    else if (path === 'index') path = '';

    var candidates = [];
    if (path) candidates.push(path);
    if (path.startsWith('/')) candidates.push(path.slice(1));
    else candidates.push('/' + path);

    var item = null;
    for (var i = 0; i < candidates.length && !item; i++) {
      var matches = document.querySelectorAll('[id="' + candidates[i].replace(/"/g, '\\"') + '"]');
      for (var j = 0; j < matches.length; j++) {
        if (matches[j].closest('#sidebar, #sidebar-content')) {
          item = matches[j];
          break;
        }
      }
    }
    if (!item) return;

    var parent = item.parentElement;
    while (parent) {
      var style = getComputedStyle(parent);
      if (style.overflowY === 'auto' || style.overflowY === 'scroll') break;
      parent = parent.parentElement;
    }
    if (!parent) return;

    var parentRect = parent.getBoundingClientRect();
    var itemRect = item.getBoundingClientRect();
    if (itemRect.top >= parentRect.top && itemRect.bottom <= parentRect.bottom) return;

    var itemTopRelative = itemRect.top - parentRect.top + parent.scrollTop;
    parent.scrollTop = itemTopRelative - parentRect.height / 2 + itemRect.height / 2;
  } catch (e) {}
})();

style.ul:
`. When there are
 * more tabs than fit the content width, the list scrolls horizontally but
 * the edge truncates cleanly on the word boundary with no affordance that
 * more tabs exist.
 *
 * Apply a mask-image fade to the trailing edge so clipped content fades
 * out instead of cutting off sharply. In browsers that support
 * scroll-driven animations (Chromium 115+, Firefox 138+, Safari 26+), the
 * mask is animated against the list's own scroll position so only the
 * side(s) with hidden content are faded. In older browsers, the static
 * right-edge fade alone still reads as "there's more here".
 *
 * When the tablist is not scrollable, the mask fades only the trailing
 * sliver of the flex-gap region (which contains no tab content), so the
 * visual effect is imperceptible.
 */
[data-component-part="tabs-list"] {
  -webkit-mask-image:
    linear-gradient(
      to right,
      #000 0,
      #000 calc(100% - 1.5rem),
      transparent 100%
    );
  mask-image:
    linear-gradient(
      to right,
      #000 0,
      #000 calc(100% - 1.5rem),
      transparent 100%
    );
}

@supports (animation-timeline: scroll()) {
  [data-component-part="tabs-list"] {
    animation: tabs-overflow-mask linear both;
    animation-timeline: scroll(self inline);
  }

  @keyframes tabs-overflow-mask {
    0% {
      -webkit-mask-image:
        linear-gradient(
          to right,
          #000 0,
          #000 calc(100% - 1.5rem),
          transparent 100%
        );
      mask-image:
        linear-gradient(
          to right,
          #000 0,
          #000 calc(100% - 1.5rem),
          transparent 100%
        );
    }
    1%,
    99% {
      -webkit-mask-image:
        linear-gradient(
          to right,
          transparent 0,
          #000 1.5rem,
          #000 calc(100% - 1.5rem),
          transparent 100%
        );
      mask-image:
        linear-gradient(
          to right,
          transparent 0,
          #000 1.5rem,
          #000 calc(100% - 1.5rem),
          transparent 100%
        );
    }
    100% {
      -webkit-mask-image:
        linear-gradient(
          to right,
          transparent 0,
          #000 1.5rem,
          #000 100%
        );
      mask-image:
        linear-gradient(
          to right,
          transparent 0,
          #000 1.5rem,
          #000 100%
        );
    }
  }
}

html[data-current-path$="/deepagents/code/overview"] breadcrumb-list,
html[data-current-path$="/deepagents/code/overview"] .breadcrumb-list {
  display: none !important;
}

/* Agent development lifecycle diagram (home page) */
/* HTML panels + SVG arrow layer: Mintlify's MDX renderer strips SVG  and
   , so labels are HTML and arrowheads are drawn as  triangles. */
.adl-engine { position: relative; max-width: 1180px; margin: 2.5rem auto; container-type: inline-size; display: flex; flex-direction: column; align-items: center; }
.adl-engine-box { text-align: center; background: #E5F4FF; border: 1.5px solid #006DDD; border-radius: 16px; padding: 1.4cqw 3cqw; margin-bottom: 2cqw; }
.adl-engine-title { font-weight: 600; font-size: clamp(20px, 3.2cqw, 34px); color: #0a1929; text-decoration: none; }
.adl-engine-title:hover { text-decoration: underline; }
.adl-engine-tagline { font-size: clamp(13px, 1.9cqw, 22px); color: #40668d; margin-top: 0.4cqw; }
.adl-board { position: relative; width: 100%; max-width: 1100px; margin: 1.5rem auto 0; aspect-ratio: 1200 / 780; container-type: inline-size; z-index: 1; }
.adl-arrows { position: absolute; inset: 0; width: 100%; height: 100%; pointer-events: none; z-index: 0; }
.adl-arrow { stroke: #6aa3d0; stroke-width: 2; stroke-dasharray: 3 6; fill: none; }
.adl-arrow-head { fill: #6aa3d0; }

.adl-panel { position: absolute; box-sizing: border-box; border-radius: 16px; background: #E5F4FF; border: 1.5px solid #006DDD; padding: 1.4cqw; display: flex; flex-direction: column; gap: 1cqw; z-index: 1; }
.adl-panel-title { color: #00355c; font-weight: 600; font-size: clamp(13px, 2cqw, 22px); line-height: 1.1; }
.adl-pills { display: grid; grid-template-columns: 1fr 1fr; gap: 0.8cqw; flex: 1; align-content: center; }
.adl-pill { display: flex; align-items: center; justify-content: center; text-align: center; background: #ffffff; border: 1px solid #b8d8f0; border-radius: 8px; color: #0a3553; font-size: clamp(9px, 1.25cqw, 14px); font-weight: 500; text-decoration: none; padding: 0.7cqw 0.4cqw; line-height: 1.15; transition: background .15s ease, border-color .15s ease, color .15s ease; }
.adl-pill:hover { background: #cde7fa; border-color: #006DDD; color: #003f7a; }

.adl-hub { position: absolute; left: 50%; top: 43.5%; transform: translate(-50%, -50%); display: flex; flex-direction: column; align-items: center; gap: 1cqw; z-index: 1; }
.adl-hub-pill { display: flex; align-items: center; justify-content: center; text-align: center; background: #33415a; color: #ffffff; border-radius: 12px; font-size: clamp(12px, 1.7cqw, 20px); font-weight: 600; text-decoration: none; padding: 1cqw 2.2cqw; white-space: nowrap; transition: background .15s ease; }
a.adl-hub-pill:hover { background: #45577a; }

.adl-govern { position: absolute; left: 38%; width: 24%; top: 84%; display: flex; flex-direction: column; align-items: center; gap: 0.8cqw; z-index: 1; }
.adl-govern-title { color: #006DDD; font-weight: 600; font-size: clamp(12px, 1.8cqw, 20px); }
.adl-govern .adl-pill { width: 75%; }

.dark .adl-arrow { stroke: #4a7ca0; }
.dark .adl-arrow-head { fill: #4a7ca0; }
.dark .adl-panel { background: #102a3f; border-color: #4ba8e8; }
.dark .adl-panel-title { color: #b8d8f0; }
.dark .adl-pill { background: #0d1b27; border-color: #2c4a66; color: #cce5fb; }
.dark .adl-pill:hover { background: #1a3a52; border-color: #6cb6ee; color: #ffffff; }
.dark .adl-govern-title { color: #6cb6ee; }
.dark .adl-engine-title { color: #e6f4ff; }
.dark .adl-engine-tagline { color: #6cb6ee; }
.dark .adl-engine-box { background: #102a3f; border-color: #4ba8e8; }
.dark .adl-hub-pill { background: #1b2737; color: #cfe0f2; }
.dark a.adl-hub-pill:hover { background: #27374d; }

