 linear-gradient(
 to right,
 transparent 0,
 #000 1.5rem,
 #000 calc(100% - 1.5rem),
 transparent 100%
 );
 mask-image:
 linear-gradient(
 to right,
 transparent 0,
 #000 1.5rem,
 #000 calc(100% - 1.5rem),
 transparent 100%
 );
 }
 100% {
 -webkit-mask-image:
 linear-gradient(
 to right,
 transparent 0,
 #000 1.5rem,
 #000 100%
 );
 mask-image:
 linear-gradient(
 to right,
 transparent 0,
 #000 1.5rem,
