a.adl-hub-pill:hover { background: #45577a; }

.adl-govern { position: absolute; left: 38%; width: 24%; top: 84%; display: flex; flex-direction: column; align-items: center; gap: 0.8cqw; z-index: 1; }
.adl-govern-title { color: #006DDD; font-weight: 600; font-size: clamp(12px, 1.8cqw, 20px); }
.adl-govern .adl-pill { width: 75%; }

.dark .adl-arrow { stroke: #4a7ca0; }
